import { describe, it, expect, beforeEach, afterEach } from "vitest";
import { mkdtempSync, mkdirSync, writeFileSync, rmSync } from "node:fs";
import { join } from "node:path";
import { tmpdir } from "node:os";
import { scoreSelfDescribing } from "../../../src/analyzers/scorers/self-describing-scorer.js";
import { MIN_INSTRUCTION_FILE_LINES, MIN_KEYWORD_HITS, INSTRUCTION_COVERAGE_KEYWORDS } from "../../../src/analyzers/scorers/scorer-utils.js";

let dir: string;

beforeEach(() => { dir = mkdtempSync(join(tmpdir(), "fc-sd-")); });
afterEach(() => { rmSync(dir, { recursive: true, force: true }); });

function writeInstruction(filename: string, content: string) {
  const full = join(dir, filename);
  const parent = full.substring(0, full.lastIndexOf("/") === -1 ? full.lastIndexOf("\\") : full.lastIndexOf("/"));
  if (parent !== full) mkdirSync(parent, { recursive: true });
  writeFileSync(full, content, "utf-8");
}

function substantiveContent(extraKeywords: string[] = []): string {
  const base = [
    ...INSTRUCTION_COVERAGE_KEYWORDS.slice(0, MIN_KEYWORD_HITS),
    ...extraKeywords,
  ].join("\n");
  const lines = Array.from({ length: MIN_INSTRUCTION_FILE_LINES + 5 }, (_, i) => `line ${i}`);
  return [base, ...lines].join("\n");
}

describe("score 0 — no instruction file", () => {
  it("returns score 0 when directory is empty", () => {
    const result = scoreSelfDescribing(dir);
    expect(result.score).toBe(0);
    expect(result.property).toBe("self-describing");
    expect(result.evidence[0]).toMatch(/No AI assistant instruction file/);
  });
});

describe("score 1 — file found but stub", () => {
  it("returns score 1 for CLAUDE.md with fewer than MIN lines", () => {
    writeFileSync(join(dir, "CLAUDE.md"), "# Project\nA short file.\n", "utf-8");
    const result = scoreSelfDescribing(dir);
    expect(result.score).toBe(1);
    expect(result.evidence[0]).toMatch(/non-empty lines/);
  });

  it("returns score 1 for CLAUDE.md with enough lines but too few keywords", () => {
    const lines = Array.from({ length: MIN_INSTRUCTION_FILE_LINES + 1 }, (_, i) => `line ${i}`).join("\n");
    writeFileSync(join(dir, "CLAUDE.md"), lines, "utf-8");
    const result = scoreSelfDescribing(dir);
    expect(result.score).toBe(1);
    expect(result.evidence.some((e) => e.includes("Missing keywords"))).toBe(true);
  });

  it("returns score 1 for .clinerules stub", () => {
    writeFileSync(join(dir, ".clinerules"), "short\n", "utf-8");
    const result = scoreSelfDescribing(dir);
    expect(result.score).toBe(1);
  });

  it("returns score 1 for .windsurfrules stub", () => {
    writeFileSync(join(dir, ".windsurfrules"), "short\n", "utf-8");
    const result = scoreSelfDescribing(dir);
    expect(result.score).toBe(1);
  });

  it("returns score 1 for CONVENTIONS.md stub", () => {
    writeFileSync(join(dir, "CONVENTIONS.md"), "short\n", "utf-8");
    const result = scoreSelfDescribing(dir);
    expect(result.score).toBe(1);
  });
});

describe("score 2 — substantive instruction file", () => {
  it("returns score 2 for CLAUDE.md with enough lines and keywords", () => {
    writeFileSync(join(dir, "CLAUDE.md"), substantiveContent(), "utf-8");
    const result = scoreSelfDescribing(dir);
    expect(result.score).toBe(2);
    expect(result.evidence[0]).toMatch(/CLAUDE\.md found/);
    expect(result.evidence[1]).toMatch(/Covers:/);
  });

  it("returns score 2 for copilot-instructions.md", () => {
    const ghDir = join(dir, ".github");
    mkdirSync(ghDir, { recursive: true });
    writeFileSync(join(ghDir, "copilot-instructions.md"), substantiveContent(), "utf-8");
    const result = scoreSelfDescribing(dir);
    expect(result.score).toBe(2);
  });

  it("prefers CLAUDE.md when multiple instruction files exist", () => {
    writeFileSync(join(dir, "CLAUDE.md"), substantiveContent(), "utf-8");
    writeFileSync(join(dir, "CONVENTIONS.md"), substantiveContent(), "utf-8");
    const result = scoreSelfDescribing(dir);
    expect(result.evidence[0]).toMatch(/CLAUDE\.md/);
  });

  it("evidence line reports correct non-empty line count", () => {
    const content = substantiveContent();
    const nonEmptyCount = content.split("\n").filter((l) => l.trim().length > 0).length;
    writeFileSync(join(dir, "CLAUDE.md"), content, "utf-8");
    const result = scoreSelfDescribing(dir);
    expect(result.evidence[0]).toContain(String(nonEmptyCount));
  });

  it("returns score 2 when file has exactly MIN_INSTRUCTION_FILE_LINES non-empty lines", () => {
    // Kills EqualityOperator L37: < MIN_INSTRUCTION_FILE_LINES → <= (40 <= 40 = true → score 1)
    const keywords = INSTRUCTION_COVERAGE_KEYWORDS.slice(0, MIN_KEYWORD_HITS).join("\n");
    const filler = Array.from({ length: MIN_INSTRUCTION_FILE_LINES - MIN_KEYWORD_HITS }, (_, i) => `line ${i}`);
    const content = [keywords, ...filler].join("\n");
    const nonEmptyCount = content.split("\n").filter((l) => l.trim().length > 0).length;
    expect(nonEmptyCount).toBe(MIN_INSTRUCTION_FILE_LINES);
    writeFileSync(join(dir, "CLAUDE.md"), content, "utf-8");
    const result = scoreSelfDescribing(dir);
    expect(result.score).toBe(2);
  });

  it("blank lines are excluded from non-empty line count", () => {
    // Kills EqualityOperator L35: > 0 → >= 0 (blank lines counted, inflating count)
    // File has MIN-1 non-blank lines, so normally score 1 (stub).
    // With mutation, blank lines count, potentially reaching MIN.
    const keywords = INSTRUCTION_COVERAGE_KEYWORDS.slice(0, MIN_KEYWORD_HITS).join("\n");
    const nonBlankLines = MIN_INSTRUCTION_FILE_LINES - 1 - MIN_KEYWORD_HITS;
    const filler = Array.from({ length: nonBlankLines }, (_, i) => `line ${i}`);
    const blanks = Array.from({ length: 10 }, () => "");
    const content = [keywords, ...filler, ...blanks].join("\n");
    writeFileSync(join(dir, "CLAUDE.md"), content, "utf-8");
    const result = scoreSelfDescribing(dir);
    expect(result.score).toBe(1);
    expect(result.evidence[0]).toMatch(/non-empty lines/);
  });
});

describe("score 1 — missing keywords evidence", () => {
  it("lists specific missing keywords in evidence", () => {
    // Kills BooleanLiteral L49 and ArrowFunction L49
    // (!lower.includes(kw) → false would make missing list empty)
    const lines = Array.from({ length: MIN_INSTRUCTION_FILE_LINES + 1 }, (_, i) => `line ${i}`).join("\n");
    const content = `architecture\n${lines}`;
    writeFileSync(join(dir, "CLAUDE.md"), content, "utf-8");
    const result = scoreSelfDescribing(dir);
    expect(result.score).toBe(1);
    const missingLine = result.evidence.find((e) => e.includes("Missing keywords")) ?? "";
    expect(missingLine.length).toBeGreaterThan("Missing keywords: ".length);
  });
});

